UPDATE chat_room_members
SET last_read_message_id = (
    SELECT cr.last_message_id
    FROM chat_rooms cr
    WHERE cr.room_id = #{roomId}
),
    unread_count = 0,
    last_read_at = NOW()
WHERE room_id = #{roomId}
